// src/components/ListaPacientes.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ListaPacientes({ reloadKey, onEditar }) {
  const [pacientes, setPacientes] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [busca, setBusca] = useState('');

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/pacientes')
      .then(res => {
        setPacientes(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm('Deletar este paciente?')) {
      axios.delete(`/api/pacientes/${id}`)
        .then(() => setPacientes(prev => prev.filter(p => p.id !== id)));
    }
  };

  const pacientesFiltrados = pacientes.filter(p => {
    const term = busca.toLowerCase();
    return (
      (p.numero_prontuario || '').toLowerCase().includes(term) ||
      p.nome.toLowerCase().includes(term) ||
      p.telefone.toLowerCase().includes(term)
    );
  });

  if (carregando) return <p>Carregando pacientes...</p>;
  if (pacientes.length === 0) return <p>Nenhum paciente cadastrado.</p>;

  return (
    <div className="mx-auto py-2 px-2">
      {/* Campo de busca */}
      <div className="mb-4">
        <input
          type="text"
          value={busca}
          onChange={e => setBusca(e.target.value)}
          placeholder="Buscar por prontuário, nome ou telefone"
          className="w-full border rounded px-3 py-2"
        />
      </div>

      <div className="bg-white rounded-2xl p-2">
        {/* Cabeçalho das colunas (desktop) */}
        <div className="hidden md:grid grid-cols-4 gap-x-4 px-2 py-2 bg-gray-100 rounded-t-xl font-semibold text-gray-600 mb-2">
          <span className="w-32">Número do Prontuário</span>
          <span>Nome</span>
          <span>Telefone</span>
          <span className="text-right">Ações</span>
        </div>
        {/* Lista */}
        <div className="space-y-3">
          {pacientesFiltrados.map((p) => (
            <div
              key={p.id}
              className="flex flex-col md:grid md:grid-cols-4 gap-y-1 gap-x-4 items-center bg-gray-50 rounded-xl px-4 md:px-2 py-2 shadow-sm hover:bg-gray-100 transition"
            >
              <div className="w-32 font-medium text-gray-800 truncate">
                {p.numero_prontuario}
              </div>
              <div className="w-full font-medium text-gray-800 truncate">
                {p.nome}
              </div>
              <div className="w-full text-gray-500">
                {p.telefone}
              </div>
              <div className="flex flex-row justify-end gap-2 w-full md:justify-end">
                <button
                  onClick={() => onEditar(p)}
                  className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
                >
                  Editar
                </button>
                <button
                  onClick={() => handleDeletar(p.id)}
                  className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
                >
                  Deletar
                </button>
              </div>
            </div>
          ))}
          {pacientesFiltrados.length === 0 && (
            <p className="text-center text-gray-500">Nenhum paciente encontrado.</p>
          )}
        </div>
      </div>
    </div>
  );
}

export default ListaPacientes;
